# Basic try/except
try:
    result = 10 / 0
except ZeroDivisionError:
    print('Cannot divide by zero!')

# Multiple exceptions
def safe_convert(s):
    try:
        return int(s)
    except ValueError:
        return None

# finally always runs
def read_file(path):
    f = None
    try:
        f = open(path)
        return f.read()
    except FileNotFoundError:
        return ''
    finally:
        if f:
            f.close()  # always close!

# Custom exception
class NegativeAmountError(Exception):
    pass

def deposit(amount):
    if amount < 0:
        raise NegativeAmountError(f'Amount cannot be negative: {amount}')
    return amount

